function ModelHeroBook:GetActiveLevelByStoryNum(num)
    local ref = GameTable.CharacterFavorabilityRef
    local tempList = {}
    for i, v in pairs(ref) do
        local unlockStoryNum = v.unlockStoryNum
        unlockStoryNum = string.split(unlockStoryNum,"|")
        if num == tonumber(unlockStoryNum[#unlockStoryNum]) then
            table.insert(tempList,v)
        end
    end
    table.sort(tempList,function(a, b)
        return a.refId < b.refId
    end)
    return tempList[1].refId
end

function ModelHeroBook:GetCharacterLevelByStoryNum(num)
    local ref = GameTable.CharacterFavorabilityRef
    local tempList = {}
    for i, v in pairs(ref) do
        local spCharacter = v.spCharacter
        spCharacter = string.split(spCharacter,"|")
        local length = #spCharacter
        for i = 1, length do
            table.removeidata(spCharacter,"0")
        end
        if num == #spCharacter then
            table.insert(tempList,v)
        end
    end
    table.sort(tempList,function(a, b)
        return a.refId < b.refId
    end)
    return tempList[1].refId
end


function ModelHeroBook:InitHeroStoryRef()
    local initHeroStoryRefList = self._initHeroStoryRefList
    if not initHeroStoryRefList then
        initHeroStoryRefList = {}
        self._initHeroStoryRefList = initHeroStoryRefList
    end
    local heroStoryKeyList = self._heroStoryKeyList
    if not heroStoryKeyList then
        heroStoryKeyList = {}
        self._heroStoryKeyList = heroStoryKeyList
    end

    for k, v in pairs(GameTable.CharacterStoryRef) do
        local storyType = v.type
        local storyList = initHeroStoryRefList[storyType]
        if not storyList then
            storyList = {}
            initHeroStoryRefList[storyType] = storyList
        end
        local refId = v.refId
        local storyData = storyList[refId]
        if not storyData then
            storyData = {
                refId = k,
                type = v.type,
                number = v.number,
                needStar = v.needStar,
                decName = v.decName,
                dec = v.dec,
                reward = v.reward,
                character = v.character,
            }
            storyList[refId] = storyData
        end
        heroStoryKeyList[refId] = storyType

        local rewardList = {}
        local reward = string.split(v.reward, ",")
        for idx, val in ipairs(reward) do
            local valList = string.split(val, "=")
            local itemType, itemRefId, itemNum = tonumber(valList[1]), tonumber(valList[2]), tonumber(valList[3])
            table.insert(rewardList, {
                itemType = itemType,
                itemRefId = itemRefId,
                itemNum = itemNum,
            })
        end
        storyData.rewardList = rewardList
    end
end

function ModelHeroBook:InitHeroRelationRef()
    local initHeroRelationRefList = self._initHeroRelationRefList
    if not initHeroRelationRefList then
        initHeroRelationRefList = {}
        self._initHeroRelationRefList = initHeroRelationRefList
    end
    for k, v in pairs(GameTable.CharacterRelationRef) do
        local refId = v.refId
        local refIdList = initHeroRelationRefList[refId]
        if not refIdList then
            refIdList = v
            initHeroRelationRefList[refId] = refIdList
        end

        local relationHeroList = {}
        local relationHeroKeyList = {}
        local relationHero = string.split(v.relationHero, "|")
        for idx, val in ipairs(relationHero) do
            local heroRefId = tonumber(val)
            table.insert(relationHeroList, heroRefId)
            relationHeroKeyList[heroRefId] = heroRefId
        end
        refIdList.relationHeroList = relationHeroList
        refIdList.relationHeroKeyList = relationHeroKeyList

        local rewardList = {}
        local reward = string.split(v.reward, ",")
        for idx, val in ipairs(reward) do
            local valList = string.split(val, "=")
            local itemType, itemRefId, itemNum = tonumber(valList[1]), tonumber(valList[2]), tonumber(valList[3])
            table.insert(rewardList, {
                itemType = itemType,
                itemId = itemRefId,
                itemNum = itemNum,
            })
        end
        refIdList.rewardList = rewardList
    end
end

