--- Get Star RedPoint 
function ModelHeroBook:GetFavorabilityGiftRed(heroRefId)
    -- 好感判定 修改为 星级判定
    local serverData = self:GetHeroInfoByHeroRefId(heroRefId)
    if not serverData then
        return
    end

    --构建奖励数据
    local heroRef = gModelHero:GetHeroRef(heroRefId)
    local heroStory = heroRef.heroStory
    if type(heroStory) == "string" then
        heroStory = tonumber(ccLngText(heroStory))
    end
    local storyRefList = self._initHeroStoryRefList[heroStory]

    if storyRefList == nil then
        storyRefList = self._initHeroStoryRefList[2000] -- 兼容配置没有 使用2000类型故事
    end
    local storyData = {}
    for k, v in pairs(storyRefList) do
        table.insert(storyData, v)
    end
    table.sort(storyData, function(a, b)
        return a.needStar < b.needStar
    end)

    local isActive = serverData.isActive

    local rewardStoryData = nil
    --遍历 
    for k, v in pairs(storyData) do
        local islock = true

        if serverData.heroMaxStar then
            islock = serverData.heroMaxStar >= v.needStar
        end

        rewardStoryData = v

        local got = rewardStoryData and serverData.storyRewardsKey[rewardStoryData.refId] ~= nil

        local canGet = isActive and not got and islock

        
        local haveReward = not string.isempty(v.reward)

        canGet =canGet and haveReward
        if canGet then
            return canGet
        end
    end

    return false
end

function ModelHeroBook:GetHeroGradeByHeroRefId(heroRefId)
    local bookInfoList = self._bookInfoList
    if not bookInfoList then
        return 0
    end
    local heroInfo = bookInfoList[heroRefId]
    local ret = 0
    if heroInfo then
        ret = heroInfo.closeGrade
    end
    return ret
end

function ModelHeroBook:GetHeroIsActByRefId(refId)
    local status = 0
    local serverData = self:GetHeroInfoByHeroRefId(refId)
    if serverData then
        local isActive = serverData.isActive
        status = isActive and 1 or 0
    end
    return status
end

function ModelHeroBook:GetHeroRelationActNum(refId)
