end

function ModelHeroBook:GetSortRelationInfoList()
    local relationList = self._relationList
    if not relationList then
        return
    end
    local retList = {}
    for k, v in pairs(relationList) do
        local serverData = v:GetServerData()
        table.insert(retList, serverData)
    end
    table.sort(retList, function(a, b)
        return a.refId < b.refId
    end)
    return retList
end

function ModelHeroBook:GetRelationInfoByRefId(refId)
    local relationList = self._relationList
    if not relationList then
        return
    end
    local struct = relationList[refId]
    if struct then
        return struct:GetServerData()
    end
end

function ModelHeroBook:GetCommentNumByHTypeAndHeroRefId(hType, refId)
    if not refId and not hType then
        return
    end
    local commentNumList = self._commentNumList
    if not commentNumList then
        self:OnCommentNumReq(hType, refId)
        return
    end
    local typeCommentNumList = commentNumList[hType]
    if not typeCommentNumList then
        self:OnCommentNumReq(hType, refId)
        return
    end
    local num = typeCommentNumList[refId]
    if not num then
        self:OnCommentNumReq(hType, refId)
        return
    end
    return num
end
