-- 图鉴列表
function ModelHeroBook:OnHeroBookListResp(pb, ret)
    local bookInfoList = self._bookInfoList
    if not bookInfoList then
        bookInfoList = {}
        self._bookInfoList = bookInfoList
    end

    local oldBookInfoList = self._oldBookInfoList
    if not oldBookInfoList then
        oldBookInfoList = {}
        self._oldBookInfoList = oldBookInfoList
    end

    local books = pb.books
    for i, v in ipairs(books) do
        local heroRefId = v.heroRefId
        local bookInfo = bookInfoList[heroRefId]
        if not bookInfo then
            bookInfo = StructBookInfo:New()
            bookInfoList[heroRefId] = bookInfo
        end
        bookInfo:CreateByPb(v)

        local active = bookInfo:GetIsActive()
        oldBookInfoList[heroRefId] = active
    end
    gModelHero:CheckNeedTranslateResType()
    FireEvent(EventNames.On_Hero_Change)
end

-- 羁绊列表
function ModelHeroBook:OnHeroRelationListResp(pb, ret)
    local relationList = self._relationList
    if not relationList then
        relationList = {}
        self._relationList = relationList
    end
    local relations = pb.relations
    for i, v in ipairs(relations) do
        local refId = v.refId
        local relationInfo = relationList[refId]
        if not relationInfo then
            relationInfo = StructRelationInfo:New()
            relationList[refId] = relationInfo
        end
        relationInfo:CreateByPb(v)
    end
    FireEvent(EventNames.On_Hero_Change)
end

-- 图鉴变化通知
function ModelHeroBook:OnBookChangeInfoResp(pb, ret)
    local bookInfoList = self._bookInfoList
    if not bookInfoList then
        bookInfoList = {}
        self._bookInfoList = bookInfoList
    end
    local bookChange = pb.bookChange
    for i, v in ipairs(bookChange) do
        local syncType = v.syncType
        local book = v.book
        local heroRefId = book.heroRefId
        if syncType == 2 then
            bookInfoList[heroRefId] = nil
        else
            local bookInfo = bookInfoList[heroRefId]
            if not bookInfo then
                bookInfo = StructBookInfo:New()
                bookInfoList[heroRefId] = bookInfo
            end
            bookInfo:CreateByPb(book)
        end
    end
    gModelHero:CheckNeedTranslateResType()
    FireEvent(EventNames.On_Hero_Change)
end

-- 羁绊变化通知
function ModelHeroBook:OnRelationChangeInfoResp(pb, ret)
    local relationList = self._relationList
    if not relationList then
        relationList = {}
        self._relationList = relationList
    end
    local relationChange = pb.relationChange
    for i, v in ipairs(relationChange) do
        local syncType = v.syncType
        local relation = v.relation
        local refId = relation.refId
        if syncType == 2 then
            relationList[refId] = nil
        else
            local relationInfo = relationList[refId]
            if not relationInfo then
                relationInfo = StructRelationInfo:New()
                relationList[refId] = relationInfo
            end
            relationInfo:CreateByPb(relation)
        end
    end
    FireEvent(EventNames.On_Hero_Change)
end

