function ModelHeroBook:OpenCommonBarrage(barrageInfo)
    if not barrageInfo then
        printInfoNR("没有数据")
        return
    end
    local loopCd = barrageInfo.loopCd
    if loopCd == nil then
        loopCd = gModelHero:GeConfigByKey("heroBarrageLoopCd")
        printInfoNR("heroBarrageLoopCd字段用来表示播放完所有弹幕数量后，间隔秒数后再重头请求，单位秒，默认" .. ModelHeroBook.HERO_BARRAGE_LOOPTIME)
    end
    if loopCd == nil then
        loopCd = ModelHeroBook.HERO_BARRAGE_LOOPTIME
    end
    gModelGeneral:OpenCommonBarrage({
        barrageList = barrageInfo.barrageList or {},
        cd = barrageInfo.cd,
        colorList = barrageInfo.colorList or {},
        autoRun = barrageInfo.autoRun,
        repeatRun = barrageInfo.repeatRun or false,
        isAutoAdd = barrageInfo.isAutoAdd,
        moveSpeed = barrageInfo.moveSpeed,
        maxShowBarrage = barrageInfo.maxShowBarrage,
        barrageType = barrageInfo.barrageType or ModelHeroBook.BARRAGE_TYPE_OTHERBARRAGE,
        loopCd = loopCd,
        heroRefId = barrageInfo.heroRefId
    })
end

function ModelHeroBook:SetHeroBookInfoList()
    local bookInfoList = self._bookInfoList
    for k, v in pairs(bookInfoList) do
        self._oldBookInfoList[k] = v.isActive
    end
end

function ModelHeroBook:FindIsNewActHeroInfoByRefId(heroRefId, onlyStatus)
    local bookInfoList = self._bookInfoList
    if not bookInfoList then
        return false
    end
    local oldBookInfoList = self._oldBookInfoList
    if not oldBookInfoList then
        return false
    end
    local oldStatus = oldBookInfoList[heroRefId]
    if oldStatus == nil then
        printInfoNR("====== 无配置英雄")
        return false
    end
    local bookInfo = bookInfoList[heroRefId]
    local newStatus = bookInfo and bookInfo.isActive or false
    if newStatus and not oldStatus then
        if onlyStatus == nil then
            oldBookInfoList[heroRefId] = true
        end
        return true
    else
        return false
    end
end

function ModelHeroBook:OpenRelationHeroAddAttrWnd(relationInfoList)
    local list = {}
    relationInfoList = relationInfoList or self._relationList
    for k, v in pairs(relationInfoList or {}) do
        local activeNumList = v.activeNumList or {}
        for idx, val in ipairs(activeNumList) do
            local ref = self:GetHeroRelationAttrRefByRelationTypeAndRefId(nil, val)
            if ref then
                for aIdx, info in ipairs(ref.attrList) do
                    table.insert(list, {
                        refId = info.refId,
                        numType = info.numType,
                        value = info.value,
                    })
                end
            end
        end
    end
    GF.OpenWndTop("UIRelationSagaAddAttr", { attrList = list })
end

