function ModelHeroBook:CheckHeroBookAllRedPointStatus()
    if self:IgnoreHeroJB() then
        return false
    end
    local status = self:CheckBookInfoStatus()
    if not status then
        --- 羁绊检查
        status = self:CheckRelationInfoStatus()
    end
    return status
end

function ModelHeroBook:CheckBookStoryStatusByRefId(refId)
    if self:IgnoreHeroJB() then
        return false
    end
    local status = false
    local serverData = self:GetHeroInfoByHeroRefId(refId)
    local heroRef = gModelHero:GetHeroRef(refId)
    if heroRef and serverData then
        local isActive = serverData.isActive
        if isActive then
            local closeGrade = serverData.heroMaxStar
            local heroStory = heroRef.heroStory
            local storyRefList = gModelHeroBook:GetHeroStoryRefListByStoryType(heroStory) or {}

            for k, v in pairs(storyRefList) do
                if status then
                    break
                end
                local storyRefId = v.refId
                local storyRewardsKey = serverData.storyRewardsKey or {}
                local isAct = storyRewardsKey[storyRefId] and true or false
                local needStar = v.needStar

                --todo :  后续沟通下 修改服务器用来比较的数据
                local unLock = serverData.heroMaxStar >= needStar
                local rewardList = v.rewardList or {}
                local len = #rewardList
                status = unLock and (not isAct) and isActive and needStar <= closeGrade and len > 0
            end
        end
    end
    return status
end

