function ModelHeroBook:CheckBookInfoStatus()
    if self:IgnoreHeroJB() then
        return false
    end
    local status = false
    local bookInfoList = self._bookInfoList or {}
    for k, v in pairs(bookInfoList) do
        if status then
            break
        end
        local heroRefId = v.heroRefId
        status = self:CheckHeroBookInfoStatusByRefId(heroRefId)
    end
    return status
end

function ModelHeroBook:CheckJBSJStatusByRefId(refId)
    local status = false
    local serverData = self:GetRelationInfoByRefId(refId)
    local cardData = self:GetHeroRelationRefByRefId(refId)
    if serverData and cardData then
        if not serverData.isRec then
            local relationHeroNum = cardData.relationHeroNum
            local relationHeroList = cardData.relationHeroList or {}
            local cardHeroLen = #relationHeroList
            local heroes = serverData.heroes or {}
            local serverHeroesLen = #heroes
            if cardHeroLen == relationHeroNum then
                status = serverHeroesLen == cardHeroLen
            end
        end
    end
    return status
end

function ModelHeroBook:CheckJBJCStatusByRefId(refId)
    local status = false
    local cardData = self:GetHeroRelationRefByRefId(refId)
    if cardData then
        local _refId = cardData.refId
        local attrType = cardData.attrType
        local relationAttrRefList = self:GetHeroRelationAttrRefListByRelationType(attrType)
        local serverData = self:GetRelationInfoByRefId(_refId)
        if relationAttrRefList and serverData then
            local heroes = serverData.heroes or {}
            local heroLen = #heroes
            local activeNumKeyList = serverData.activeNumKeyList or {}
            for k, v in pairs(relationAttrRefList) do
                if status then
                    break
                end
                local relationAttrRefId = v.refId
                local need = v.need
                local isAct = heroLen >= need
                if isAct then
                    if not activeNumKeyList[relationAttrRefId] then
                        status = true
                    end
                end
            end
        end
    end
    return status
end

function ModelHeroBook:CheckHeroRelationInfoStatusByRefId(refId)
    local status = self:CheckJBSJStatusByRefId(refId)
    if not status then
        status = self:CheckJBJCStatusByRefId(refId)
    end
    return status
end

function ModelHeroBook:CheckRelationInfoStatus()
    if self:IgnoreHeroJB() then
        return false
    end
    local status = false
    --local isOpen = gModelFunctionOpen:CheckIsOpened(10303003)
    local isOpen = false
    if not isOpen then
        return status
    end
    local relationList = self._relationList or {}
    for k, v in pairs(relationList) do
        if status then
            break
        end
        local relationRefId = v.refId
        status = self:CheckHeroRelationInfoStatusByRefId(relationRefId)
    end
    return status
end

function ModelHeroBook:GetHeroRecommendRefListByHeroRefId(heroRefId)
    --- 英雄的RefId
    local initHeroRecommendDataList = self._initHeroRecommendDataList
    if not initHeroRecommendDataList then
        initHeroRecommendDataList = {}
        self._initHeroRecommendDataList = initHeroRecommendDataList
        local hero
        for k, v in pairs(GameTable.CharacterCommentRef) do
            hero = v.hero
            local data = initHeroRecommendDataList[hero]
            if not data then
                data = {}
                initHeroRecommendDataList[hero] = data
            end
            table.insert(data, v)
        end
    end
    return initHeroRecommendDataList[heroRefId] or {}
end

function ModelHeroBook:GetHeroRecommendTxtByRefId(refId)
    if not refId then
        return ""
    end
    local ref = self:GetHeroCommentRefByRefId(refId)
    if ref then
        return ccLngText(ref.commentTxt)
    end
end

function ModelHeroBook:GetHeroCommentRefByRefId(refId)
    return GameTable.CharacterCommentRef[refId]
end


