function ModelHeroBook:CheckIsShowHeroBook()
    if not gModelFunctionOpen:CheckIsShow(10303000) then return false end
    if PRODUCT_G_VER == 2 and gLGameLanguage:IsJapanRegion() then return false end
    local ignoreResTypeMap = self._ignoreResTypeMap
    if not ignoreResTypeMap then
        ignoreResTypeMap = {}
        local ignoreResType = gModelHero:GeConfigByKey("ignoreResType")
        if ignoreResType then
            ignoreResType = string.split(ignoreResType,"|")
            for i,v in ipairs(ignoreResType) do
                v = checknumber(v)
                ignoreResTypeMap[v] = v
            end
        else
            ignoreResTypeMap[3] = 3
        end
        self._ignoreResTypeMap = ignoreResTypeMap
    end
    local resType = LPlayerPrefs.GetLocalization()
    if ignoreResTypeMap[resType] then return false end

    return true
end
